<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Steel Sprout - Bespoke Metalcraft & Architectural Design</title>
  <meta name="description" content="Steel Sprout specializes in custom metal shelving, retail displays, and architectural metalwork. We merge industrial durability with magazine-quality aesthetics for discerning commercial and residential spaces in New York.">
  <link rel="icon" href="favicon.ico">
  
  <link href="https://cdn.jsdelivr.net/npm/bootstrap@5.3.2/dist/css/bootstrap.min.css" rel="stylesheet">
  
  <style>
    /* Custom styles for the editorial-elegant aesthetic */
    :root {
      --bs-font-sans-serif: 'Nunito', sans-serif;
      --bs-font-serif: 'Georgia', serif;
      --bs-primary: rgb(26, 26, 46); /* Dark primary color */
      --bs-primary-light: rgb(43, 43, 64);
      --bs-primary-dark: rgb(15, 15, 30);
      --bs-secondary: rgb(140, 140, 145);
      --bs-accent: rgb(186, 160, 122); /* Gold/bronze accent */
      --bs-background-light: rgb(248, 248, 249);
      --bs-border-radius: 8px;
    }

    body {
      font-family: var(--bs-font-sans-serif);
      color: var(--bs-primary); /* Default text color */
      background-color: var(--bs-background-light);
    }

    h1, h2, h3, h4, h5, h6 {
      font-family: var(--bs-font-serif);
      font-weight: 700;
      color: var(--bs-primary-dark); /* Darker headings */
    }

    .hero-section {
      padding-top: 5rem;
      padding-bottom: 0;
      background-color: var(--bs-primary); /* Use primary dark for consistency */
      color: var(--bs-white);
      min-height: 100vh; /* Ensure hero covers full viewport height on small screens */
    }

    .hero-image-container {
      overflow: hidden; /* Ensure image doesn't spill */
    }

    .hero-image {
      width: 100%;
      height: auto;
      display: block;
    }

    .btn-accent {
      background-color: var(--bs-accent);
      color: var(--bs-primary);
      border-color: var(--bs-accent);
      padding: 0.75rem 1.75rem;
      border-radius: var(--bs-border-radius);
      transition: all 0.3s ease-in-out;
      font-weight: 600;
    }

    .btn-accent:hover {
      background-color: var(--bs-primary);
      color: var(--bs-accent);
      border-color: var(--bs-primary);
      transform: translateY(-2px); /* Subtle lift on hover */
    }

    .section-spacing {
      padding-top: 5rem; /* Generous vertical padding */
      padding-bottom: 5rem;
    }

    .card {
      border-radius: var(--bs-border-radius);
      transition: transform 0.3s ease-out, box-shadow 0.3s ease-out;
    }

    .card.hover-translate-y:hover {
      transform: translateY(-8px); /* Medium translateY hover effect */
      box-shadow: 0 0.5rem 1rem rgba(0, 0, 0, 0.1); /* Subtle shadow on hover */
    }

    .card.border-start-accent {
      border-left: 4px solid var(--bs-accent) !important; /* Accent border on the left */
    }

    .icon-container {
      display: inline-flex;
      align-items: center;
      justify-content: center;
      width: 48px; /* Example size */
      height: 48px;
      background-color: rgba(var(--bs-accent-rgb), 0.1); /* Light accent background */
      border-radius: 12px; /* Rounded square */
    }

    .icon-container svg {
      color: var(--bs-accent);
      width: 24px;
      height: 24px;
    }

    /* Navbar styling for transparent to solid on scroll */
    .navbar-scroll {
      transition: background-color 0.3s ease-out;
    }

    .navbar-scroll.scrolled {
      background-color: var(--bs-primary) !important; /* Solid dark background when scrolled */
    }
    
    .navbar-brand {
      font-family: var(--bs-font-serif);
      font-weight: 700;
      color: var(--bs-accent) !important; /* Brand name in accent color */
    }

    .navbar-nav .nav-link {
        color: rgba(255, 255, 255, 0.8) !important; /* Lighter white for links */
        transition: color 0.2s ease-in-out;
    }

    .navbar-nav .nav-link:hover {
        color: var(--bs-accent) !important; /* Accent color on hover */
    }

    /* Ensure strong contrast for footer */
    .footer-dark-bg {
        background-color: var(--bs-primary-dark); /* Dark background */
        color: var(--bs-white); /* Light text */
    }

    .footer-dark-bg a {
        color: var(--bs-accent);
        text-decoration: none;
    }

    .footer-dark-bg a:hover {
        color: var(--bs-white);
    }

    /* Accessibility for reduced motion */
    @media (prefers-reduced-motion: reduce) {
      .card.hover-translate-y:hover {
        transform: none;
        box-shadow: none;
      }
      .btn-accent:hover {
        transform: none;
      }
    }
  </style>
</head>
